function rememberMe(username, passwordHash) {
  const expiryDate = new Date();
  expiryDate.setDate(expiryDate.getDate() + 30);

  document.cookie = `username=${username}; expires=${expiryDate.toUTCString()}; path=/`;
  document.cookie = `passwordHash=${passwordHash}; expires=${expiryDate.toUTCString()}; path=/`;
}

function autoLogin() {
  const username = document.cookie.split(';').find(cookie => cookie.includes('username='))?.split('=')[1];
  const passwordHash = document.cookie.split(';').find(cookie => cookie.includes('passwordHash='))?.split('=')[1];

  if (username && passwordHash) {
    // Perform login using username and passwordHash
  }
}

// Call autoLogin() on page load
window.addEventListener('load', autoLogin);